import{_ as n,o as t,c as i,a0 as g}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Khách hàng","description":"","frontmatter":{"title":"Khách hàng"},"headers":[],"relativePath":"customer.md","filePath":"customer.md"}'),o={name:"customer.md"};function a(r,h,c,l,d,s){return t(),i("div",null,[...h[0]||(h[0]=[g('<h1 id="khach-hang" tabindex="-1">Khách hàng <a class="header-anchor" href="#khach-hang" aria-label="Permalink to &quot;Khách hàng&quot;">​</a></h1><h2 id="khach-hang-la-gi" tabindex="-1">Khách hàng là gì? <a class="header-anchor" href="#khach-hang-la-gi" aria-label="Permalink to &quot;Khách hàng là gì?&quot;">​</a></h2><p><strong>Khách hàng</strong> (Customer) là cá nhân hoặc tổ chức mua sản phẩm hoặc dịch vụ của doanh nghiệp bạn. Trong ABNERP, khách hàng là một trong những danh mục nền tảng, được sử dụng xuyên suốt các quy trình bán hàng, CRM, kế toán và hỗ trợ.</p><h2 id="tao-khach-hang-moi" tabindex="-1">Tạo khách hàng mới <a class="header-anchor" href="#tao-khach-hang-moi" aria-label="Permalink to &quot;Tạo khách hàng mới&quot;">​</a></h2><h3 id="cac-buoc-thuc-hien" tabindex="-1">Các bước thực hiện <a class="header-anchor" href="#cac-buoc-thuc-hien" aria-label="Permalink to &quot;Các bước thực hiện&quot;">​</a></h3><ol><li>Truy cập <strong>Trang chủ &gt; Bán hàng &gt; Khách hàng</strong> (hoặc tìm kiếm &quot;Khách hàng&quot; trên thanh tìm kiếm)</li><li>Nhấn <strong>+ Thêm Khách hàng</strong></li><li>Điền thông tin chi tiết</li><li>Nhấn <strong>Lưu</strong></li></ol><h3 id="cac-truong-thong-tin" tabindex="-1">Các trường thông tin <a class="header-anchor" href="#cac-truong-thong-tin" aria-label="Permalink to &quot;Các trường thông tin&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trường</th><th>Bắt buộc</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Tên khách hàng</strong></td><td>Có</td><td>Tên đầy đủ của khách hàng (cá nhân hoặc tổ chức)</td></tr><tr><td><strong>Mã khách hàng</strong></td><td>Có</td><td>Mã định danh duy nhất (tự động sinh hoặc nhập thủ công)</td></tr><tr><td><strong>Nhóm khách hàng</strong></td><td>Có</td><td>Phân loại khách hàng (ví dụ: Cá nhân, Doanh nghiệp, VIP, Đại lý)</td></tr><tr><td><strong>Loại khách hàng</strong></td><td>Có</td><td>Phân loại theo tư cách pháp lý: Cá nhân hoặc Tổ chức</td></tr><tr><td><strong>Địa chỉ</strong></td><td>Không</td><td>Địa chỉ giao hàng và địa chỉ thanh toán</td></tr><tr><td><strong>Email</strong></td><td>Không</td><td>Địa chỉ email liên hệ</td></tr><tr><td><strong>Điện thoại</strong></td><td>Không</td><td>Số điện thoại liên hệ</td></tr><tr><td><strong>Website</strong></td><td>Không</td><td>Trang web của khách hàng (nếu có)</td></tr><tr><td><strong>Ngân hàng</strong></td><td>Không</td><td>Thông tin tài khoản ngân hàng của khách hàng</td></tr><tr><td><strong>Điều khoản thanh toán</strong></td><td>Không</td><td>Thời hạn thanh toán mặc định (30 ngày, 60 ngày, v.v.)</td></tr><tr><td><strong>Hạn mức tín dụng</strong></td><td>Không</td><td>Giới hạn công nợ tối đa</td></tr><tr><td><strong>Thuế</strong></td><td>Không</td><td>Cấu hình thuế mặc định cho khách hàng</td></tr></tbody></table><h2 id="nhom-khach-hang" tabindex="-1">Nhóm khách hàng <a class="header-anchor" href="#nhom-khach-hang" aria-label="Permalink to &quot;Nhóm khách hàng&quot;">​</a></h2><p><strong>Nhóm khách hàng</strong> (Customer Group) giúp bạn phân loại khách hàng để dễ dàng quản lý và báo cáo. Một số nhóm khách hàng phổ biến:</p><ul><li><strong>Cá nhân</strong>: Người tiêu dùng cuối</li><li><strong>Doanh nghiệp</strong>: Công ty, tổ chức</li><li><strong>VIP</strong>: Khách hàng thân thiết, doanh số cao</li><li><strong>Đại lý</strong>: Nhà phân phối, đại lý bán lẻ</li><li><strong>Chính phủ</strong>: Cơ quan nhà nước</li></ul><p>Bạn có thể tùy chỉnh nhóm khách hàng tại <strong>Trang chủ &gt; Bán hàng &gt; Nhóm khách hàng</strong>.</p><h2 id="đia-chi-va-thong-tin-lien-he" tabindex="-1">Địa chỉ và thông tin liên hệ <a class="header-anchor" href="#đia-chi-va-thong-tin-lien-he" aria-label="Permalink to &quot;Địa chỉ và thông tin liên hệ&quot;">​</a></h2><p>Mỗi khách hàng có thể có nhiều địa chỉ và người liên hệ:</p><h3 id="đia-chi-address" tabindex="-1">Địa chỉ (Address) <a class="header-anchor" href="#đia-chi-address" aria-label="Permalink to &quot;Địa chỉ (Address)&quot;">​</a></h3><ul><li><strong>Địa chỉ giao hàng</strong>: Nơi giao sản phẩm</li><li><strong>Địa chỉ thanh toán</strong>: Nơi gửi hóa đơn</li><li>Bạn có thể thêm nhiều địa chỉ cho một khách hàng và đặt địa chỉ mặc định</li></ul><h3 id="nguoi-lien-he-contact" tabindex="-1">Người liên hệ (Contact) <a class="header-anchor" href="#nguoi-lien-he-contact" aria-label="Permalink to &quot;Người liên hệ (Contact)&quot;">​</a></h3><ul><li><strong>Người đại diện</strong>: Người có thẩm quyền quyết định</li><li><strong>Người mua hàng</strong>: Người liên hệ chính về đơn hàng</li><li><strong>Người nhận hàng</strong>: Người phụ trách nhận sản phẩm</li><li>Mỗi người liên hệ có thể có email, số điện thoại và chức danh riêng</li></ul><h2 id="quy-trinh-nghiep-vu-lien-quan" tabindex="-1">Quy trình nghiệp vụ liên quan <a class="header-anchor" href="#quy-trinh-nghiep-vu-lien-quan" aria-label="Permalink to &quot;Quy trình nghiệp vụ liên quan&quot;">​</a></h2><p>Khách hàng tham gia vào các quy trình nghiệp vụ sau trong ABNERP:</p><ol><li><strong>CRM — Cơ hội</strong>: Quản lý cơ hội bán hàng từ khách hàng tiềm năng</li><li><strong>Bán hàng — Báo giá</strong>: Gửi báo giá cho khách hàng</li><li><strong>Bán hàng — Đơn đặt hàng</strong>: Xác nhận đơn hàng từ khách hàng</li><li><strong>Bán hàng — Phiếu xuất kho</strong>: Xuất hàng cho khách hàng</li><li><strong>Kế toán — Hóa đơn</strong>: Xuất hóa đơn và theo dõi công nợ</li><li><strong>Hỗ trợ — Ticket</strong>: Tiếp nhận và xử lý yêu cầu hỗ trợ</li></ol><h2 id="meo-va-luu-y" tabindex="-1">Mẹo và lưu ý <a class="header-anchor" href="#meo-va-luu-y" aria-label="Permalink to &quot;Mẹo và lưu ý&quot;">​</a></h2><ul><li>Sử dụng <strong>Nhóm khách hàng</strong> để phân loại và áp dụng chính sách giá khác nhau</li><li>Thiết lập <strong>Hạn mức tín dụng</strong> để kiểm soát công nợ và rủi ro thanh toán</li><li>Lưu đầy đủ thông tin địa chỉ và liên hệ để tự động điền vào chứng từ bán hàng</li><li>Kích hoạt <strong>Theo dõi công nợ</strong> để luôn biết khách hàng còn nợ bao nhiêu</li><li>Sử dụng báo cáo <strong>Phân tích khách hàng</strong> để đánh giá hiệu quả kinh doanh theo từng khách hàng</li></ul>',23)])])}const m=n(o,[["render",a]]);export{u as __pageData,m as default};
